VALUES
  ('optometrist-moex-01134', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關自動電腦驗光機原理之敘述，下列何者錯誤？', '["使用自動電腦驗光機測量度數屬於他覺式驗光法", "作用原理為利用遠紅外線光源入射眼介質，經折反射後分析計算出屈光不正度數", "一般所採用之遠紅外線波長介於700至800 奈米（nm）", "因受到來自脈絡膜及鞏膜反射光之影響，測量結果可能會產生約-0.50D之誤差"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 18, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01135', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列何者不屬於自覺式驗光（subjectiverefraction）步驟？', '["紅綠雙色測試（duochrometest）", "綜合驗光儀測試（phoropter）檢查", "散光盤表測試（astigmaticdialtest）", "照相驗光（photorefraction）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01136', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '關於視網膜檢影鏡法（retinoscopy）檢查時，被檢查者眼球在180度及90度的方向，皆可以+3.00D達到 中和，若檢查距離為67cm，被檢查者的屈光度數為下列何者？', '["+1.50DS", "+3.00DS", "+4.50DS", "+6.00DS"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01137', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '以綜合驗光儀進行散光檢查，初始處方為＋2.50DS/-1.25DC×065。放置圓柱交叉鏡後開始檢查散光軸度， 患者表示鏡片1較清楚，檢查者便將散光軸度調整至055。試問，此時JCC上負軸（minus axis）軸度為 何？', '["055", "145", "010", "100"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01138', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關霧視（fogging）何者錯誤？', '["霧視單側眼睛可以測試雙眼平衡（binocularbalance）", "可以藉此消除調節（accommodation）造成的配鏡誤差", "可藉由加上凸透鏡度數來達到霧視的效果", "霧視是試圖將成像移至視網膜後方，使眼睛放鬆"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01139', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '一位20歲的患者進行自覺式驗光，以紅綠雙色檢查（duochrome）一直無法調整到紅綠的視標一樣清楚， 當加入+0.25DS時紅色視標比較清楚（綠變紅），但拿掉它時又變回綠色視標比較清楚（紅變綠）。若要再 進行傑克森交叉圓柱鏡（JCC）測量散光，下列敘述何者最正確？', '["應該留在紅色視標清楚，因為紅色清楚時代表最小模糊圈（circleofleastconfusion）已經精準的在視網 膜上", "應該留在紅色視標清楚，因為紅色清楚時年輕患者可以透過調節將最小模糊圈調至視網膜上", "應該留在綠色視標清楚，因為綠色清楚時代表最小模糊圈已經精準的在視網膜上", "應該留在綠色視標清楚，因為綠色清楚時年輕患者可以透過調節將最小模糊圈調至視網膜上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01140', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '在測量-9.00DS/-3.00DC×135 的角度軸時，交叉圓柱翻轉鏡的位置其負圓柱鏡軸在 90 度時，被檢者認為 看得較清楚，當每次角度調整以5度角為準時，則其角度軸應調至多少度？', '["090", "130", "135", "140"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01141', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '進行自覺式驗光後患者的視力品質仍然不佳，因此決定運用裂孔板（stenopaeicslit）來幫患者重新確認度 數。將裂孔板放在35度時，矯正度數的鏡片為+2.50DS，又將裂孔板轉至125度，矯正度數的鏡片為 -1.00DS。依照上述，此受檢者的矯正度數應為：', '["+2.50DS/-1.00DC×035", "+2.50DS/-1.00DC×125", "+2.50DS/-3.50DC×035", "+2.50DS/-3.50DC×125"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01142', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關使用鐘面散光圖形（astigmaticdial）檢查時，患者表示在2點鐘的線條最模糊，此時在眼內何種角度 的線條最為清楚？', '["30度", "60度", "120度", "150度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01143', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關處方近用加入度（ADD）之敘述，下列何者錯誤？', '["大多數近用加入度的處方，雙眼應該一致", "若兩眼測量出的近用加入度不一樣，應重做測試或確認其遠距離處方之雙眼平衡檢查結果", "健康條件不佳的患者可能會要求高於其年齡或工作距離所需的近用加入度", "當檢查出的近用加入度低於患者年齡或工作距離所需時，應考量其遠距離處方是否有正度數不足或負度 數過量之情形"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
